320	/// Push an error for argument `arg` with extra message `extramsg`.
321	/// Attempts to enrich the message with the calling function's name.
322	/// Always returns `Err`.
323	///
324	/// C: `LUALIB_API int luaL_argerror(lua_State *L, int arg, const char *extramsg)`
325	pub fn arg_error(
326	    state: &mut LuaState,
327	    mut arg: i32,
328	    extramsg: &[u8],
329	) -> Result<usize, LuaError> {
330	    let mut ar = LuaDebug::default();
331	    if !state.get_stack(0, &mut ar) {
332	        // C: return luaL_error(L, "bad argument #%d (%s)", arg, extramsg);
333	        return Err(LuaError::runtime(format_args!(
334	            "bad argument #{} ({})",
335	            arg,
336	            BStr(extramsg)
337	        )));
338	    }
339	    state.get_info(b"n", &mut ar)?;
340	    if ar.namewhat == b"method" {
341	        arg -= 1; // do not count 'self'
342	        if arg == 0 {
343	            let name = ar.name.clone().unwrap_or_else(|| b"?".to_vec());
344	            return Err(LuaError::runtime(format_args!(
345	                "calling '{}' on bad self ({})",
346	                BStr(&name),
347	                BStr(extramsg)
348	            )));
349	        }
350	    }
351	    let fname = if ar.name.is_none() {
352	        if push_global_func_name(state, &mut ar)? {
353	            state.peek_bytes(-1).unwrap_or_else(|| b"?".to_vec())
354	        } else {
355	            b"?".to_vec()
356	        }
357	    } else {
358	        ar.name.clone().unwrap_or_else(|| b"?".to_vec())
359	    };
360	    Err(LuaError::runtime(format_args!(
361	        "bad argument #{} to '{}' ({})",
362	        arg,
363	        BStr(&fname),
364	        BStr(extramsg)
365	    )))
366	}
