705	/// Raise an error for a non-integer number argument.
706	///
707	/// C: `static void interror(lua_State *L, int arg)`
708	///
709	/// Always returns `Err`. The `Ok` arm uses `unreachable!()` to satisfy the
710	/// return type; `!` (never) is nightly-only so we use `Result<usize, LuaError>`.
711	fn int_error(state: &mut LuaState, arg: i32) -> Result<usize, LuaError> {
712	    if state.is_number(arg) {
713	        Err(LuaError::arg_error(
714	            arg,
715	            "number has no integer representation",
716	        ))
717	    } else {
718	        tag_error(state, arg, LuaType::Number)?;
719	        unreachable!("tag_error always returns Err")
720	    }
