772	/// Initialize `buf` and associate it with `state`.
773	/// Pushes a placeholder light-userdata onto `state` to anchor the buffer in C.
774	/// In Rust the Vec is self-contained; we still push a placeholder for stack-slot
775	/// compatibility with code that later calls `add_value` / `push_result`.
776	///
777	/// C: `LUALIB_API void luaL_buffinit(lua_State *L, luaL_Buffer *B)`
778	pub fn buf_init(state: &mut LuaState, buf: &mut LuaBuffer) {
779	    // PORT NOTE: C pushes a light-userdata placeholder onto the stack to hold
780	    // the buffer's position. We still push nil as a stack slot placeholder so
781	    // that add_value / push_result see the same stack layout.
782	    *buf = LuaBuffer::new();
783	    // C: lua_pushlightuserdata(L, (void*)B);  /* push placeholder */
784	    // We push nil; Phase B can revisit if this matters for GC interaction.
