1266	    state: &mut LuaState,
1267	    modname: &[u8],
1268	    openf: fn(&mut LuaState) -> Result<usize, LuaError>,
1269	    glb: bool,
1270	) -> Result<(), LuaError> {
1271	    get_subtable(state, LUA_REGISTRYINDEX, LUA_LOADED_TABLE)?;
1272	    state.get_field(-1, modname)?;
1273	    if !state.to_boolean(-1) {
1274	        state.pop_n(1);
1275	        state.push_c_function(openf)?;
1276	        state.push_bytes(modname)?;
1277	        state.call(1, 1)?;
1278	        state.push_value(-1)?;
1279	        state.set_field(-3, modname)?;
1280	    }
1281	    state.remove(-2)?;
1282	    if glb {
1283	        // C: lua_pushvalue(L, -1); lua_setglobal(L, modname);
1284	        state.push_value(-1)?;
1285	        state.set_global(modname)?;
1286	    }
1287	    Ok(())
1288	}
1289	
1290	// ── Helper for registry-based metatable lookup ─────────────────────────────────
1291	
1292	/// Push `registry[tname]` and return its type.
1293	///
1294	/// C: `#define luaL_getmetatable(L,n) (lua_getfield(L, LUA_REGISTRYINDEX, (n)))`
1295	pub fn get_metatable(state: &mut LuaState, tname: &[u8]) -> Result<LuaType, LuaError> {
1296	    state.get_field(LUA_REGISTRYINDEX, tname)
1297	}
1298	
1299	// ── State creation and version check ─────────────────────────────────────────
1300	
1301	/// Create a new `LuaState` with the default allocator, a panic handler, and
1302	/// warnings disabled.
1303	///
1304	/// C: `LUALIB_API lua_State *luaL_newstate(void)`
1305	pub fn new_state() -> Result<LuaState, LuaError> {
1306	    // C: lua_State *L = lua_newstate(l_alloc, NULL);
1307	    // PORT NOTE: Rust's allocator is used implicitly; no l_alloc hook needed.
1308	    // TODO(phase-b): LuaState::new() / set_panic_handler / set_warn_fn need a real LuaState constructor in lua-vm. Stub for Phase A.
1309	    let _ = default_panic_handler;
1310	    let _ = warn_off;
1311	    todo!("phase-b: LuaState::new()")
1312	}
1313	
1314	/// Default panic handler: print message to stderr and return to abort.
1315	///
1316	/// C: `static int panic(lua_State *L)`
1317	fn default_panic_handler(state: &mut LuaState) -> Result<usize, LuaError> {
1318	    // C: const char *msg = (lua_type(L, -1) == LUA_TSTRING) ? lua_tostring(L, -1) : "...";
1319	    let msg = if state.type_at(-1) == LuaType::String {
1320	        state.peek_bytes(-1).unwrap_or_else(|| b"?".to_vec())
1321	    } else {
1322	        b"error object is not a string".to_vec()
1323	    };
1324	    // C: lua_writestringerror(...)
1325	    eprintln!("PANIC: unprotected error in call to Lua API ({})", BStr(&msg));
1326	    Ok(0) // return to Lua to abort
1327	}
1328	
1329	/// Warning function: warnings are off.
1330	///
1331	/// C: `static void warnfoff(void *ud, const char *message, int tocont)`
1332	fn warn_off(state: &mut LuaState, message: &[u8], tocont: bool) -> Result<(), LuaError> {
1333	    check_control(state, message, tocont)?;
1334	    Ok(())
1335	}
1336	
1337	/// Warning function: ready to start a new message.
1338	///
1339	/// C: `static void warnfon(void *ud, const char *message, int tocont)`
1340	fn warn_on(state: &mut LuaState, message: &[u8], tocont: bool) -> Result<(), LuaError> {
1341	    if check_control(state, message, tocont)? {
1342	        return Ok(());
1343	    }
1344	    eprint!("Lua warning: ");
1345	    warn_cont(state, message, tocont)
1346	}
1347	
1348	/// Warning function: continue writing a previous warning message.
1349	///
1350	/// C: `static void warnfcont(void *ud, const char *message, int tocont)`
1351	fn warn_cont(state: &mut LuaState, message: &[u8], tocont: bool) -> Result<(), LuaError> {
1352	    // C: lua_writestringerror("%s", message);
1353	    eprint!("{}", BStr(message));
1354	    // TODO(phase-b): set_warn_fn expects lua_CFunction in state_stub; warn_cont/warn_on take (msg, tocont). Wire after warn-fn API lands in lua-vm.
1355	    if tocont {
1356	        let _ = (warn_cont as fn(&mut LuaState, &[u8], bool) -> Result<(), LuaError>,);
1357	    } else {
1358	        eprintln!();
1359	        let _ = (warn_on as fn(&mut LuaState, &[u8], bool) -> Result<(), LuaError>,);
1360	    }
1361	    Ok(())
1362	}
1363	
1364	/// Handle a warning control message (e.g. `"@on"`, `"@off"`).
1365	/// Returns `true` if the message was a recognised control message.
1366	///
1367	/// C: `static int checkcontrol(lua_State *L, const char *message, int tocont)`
1368	fn check_control(
1369	    state: &mut LuaState,
1370	    message: &[u8],
1371	    tocont: bool,
1372	) -> Result<bool, LuaError> {
1373	    // C: if (tocont || *(message++) != '@') return 0;
1374	    if tocont || message.first() != Some(&b'@') {
1375	        return Ok(false);
1376	    }
1377	    let cmd = &message[1..];
1378	    // TODO(phase-b): set_warn_fn expects lua_CFunction in state_stub; warn_off/warn_on take (msg, tocont). Wire after warn-fn API lands in lua-vm.
1379	    let _ = state;
1380	    if cmd == b"off" {
1381	        let _ = warn_off as fn(&mut LuaState, &[u8], bool) -> Result<(), LuaError>;
1382	    } else if cmd == b"on" {
1383	        let _ = warn_on as fn(&mut LuaState, &[u8], bool) -> Result<(), LuaError>;
1384	    }
1385	    Ok(true)
1386	}
1387	
1388	/// Version-compatibility check: error if numeric type sizes or version mismatch.
1389	///
1390	/// C: `LUALIB_API void luaL_checkversion_(lua_State *L, lua_Number ver, size_t sz)`
1391	pub fn check_version(state: &mut LuaState, ver: f64, sz: usize) -> Result<(), LuaError> {
1392	    // C: LUAL_NUMSIZES = sizeof(lua_Integer)*16 + sizeof(lua_Number)
1393	    const LUAL_NUMSIZES: usize = std::mem::size_of::<i64>() * 16 + std::mem::size_of::<f64>();
1394	    if sz != LUAL_NUMSIZES {
1395	        return Err(LuaError::runtime(format_args!(
1396	            "core and library have incompatible numeric types"
1397	        )));
1398	    }
1399	    let v = state.lua_version();
1400	    if (v - ver).abs() > f64::EPSILON {
1401	        return Err(LuaError::runtime(format_args!(
1402	            "version mismatch: app. needs {}, Lua core provides {}",
1403	            ver, v
1404	        )));
1405	    }
1406	    Ok(())
1407	}
1408	
1409	// ── Internal display helper ────────────────────────────────────────────────────
1410	
1411	/// Wrapper that implements `Display` for `&[u8]` as a lossy byte string.
1412	/// Used to embed byte slices in `format_args!` without allocating a `String`.
1413	///
1414	/// PORT NOTE: not used for Lua string data; used only for error message
1415	/// formatting inside `format_args!` literals.
1416	struct BStr<'a>(&'a [u8]);
1417	
1418	impl<'a> std::fmt::Display for BStr<'a> {
1419	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
1420	        for &b in self.0 {
1421	            if b.is_ascii() {
1422	                f.write_char(b as char)?;
1423	            } else {
1424	                write!(f, "\\x{:02x}", b)?;
1425	            }
1426	        }
1427	        Ok(())
1428	    }
1429	}
1430	
1431	// Required for fmt::Display
1432	use std::fmt::Write as _;
1433	
1434	// ── LuaDebug Default ─────────────────────────────────────────────────────────
1435	
1436	
1437	// ──────────────────────────────────────────────────────────────────────────
1438	// PORT STATUS
1439	//   source:        src/lauxlib.c  (1127 lines, ~50 functions)
1440	//   target_crate:  lua-stdlib
1441	//   confidence:    medium
1442	//   todos:         19
